import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { format } from "date-fns";
import { CalendarDays, Search, Eye, CheckCircle, XCircle, Clock, Users, Loader2 } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { toast } from "sonner";

interface BookingRecord {
  id: string;
  restaurant_name: string;
  restaurant_id: string | null;
  customer_name: string | null;
  customer_email: string;
  customer_phone: string | null;
  booking_date: string;
  booking_time: string;
  party_size: number;
  notes: string | null;
  status: string;
  created_at: string;
}

const AdminBookings = () => {
  const { t } = useTranslation();
  const [bookings, setBookings] = useState<BookingRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [selectedBooking, setSelectedBooking] = useState<BookingRecord | null>(null);
  const [updatingId, setUpdatingId] = useState<string | null>(null);

  const fetchBookings = async () => {
    setLoading(true);
    let query = supabase
      .from("booking_records")
      .select("*")
      .order("created_at", { ascending: false })
      .limit(200);

    if (statusFilter !== "all") {
      query = query.eq("status", statusFilter);
    }

    const { data, error } = await query;
    if (error) {
      toast.error(t("common.error"));
    } else {
      let filtered = data || [];
      if (search) {
        const s = search.toLowerCase();
        filtered = filtered.filter(
          (b) =>
            b.restaurant_name?.toLowerCase().includes(s) ||
            b.customer_name?.toLowerCase().includes(s) ||
            b.customer_email?.toLowerCase().includes(s) ||
            b.customer_phone?.includes(s)
        );
      }
      setBookings(filtered);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchBookings();
  }, [statusFilter]);

  useEffect(() => {
    const timer = setTimeout(fetchBookings, 400);
    return () => clearTimeout(timer);
  }, [search]);

  const updateStatus = async (id: string, newStatus: string) => {
    setUpdatingId(id);
    const { error } = await supabase
      .from("booking_records")
      .update({ status: newStatus })
      .eq("id", id);

    if (error) {
      toast.error(t("common.error"));
    } else {
      toast.success(t("common.saved"));
      setBookings((prev) =>
        prev.map((b) => (b.id === id ? { ...b, status: newStatus } : b))
      );
      if (selectedBooking?.id === id) {
        setSelectedBooking((prev) => prev ? { ...prev, status: newStatus } : null);
      }
    }
    setUpdatingId(null);
  };

  const statusBadge = (status: string) => {
    const variants: Record<string, { variant: "default" | "secondary" | "destructive" | "outline"; icon: typeof Clock }> = {
      pending: { variant: "secondary", icon: Clock },
      confirmed: { variant: "default", icon: CheckCircle },
      cancelled: { variant: "destructive", icon: XCircle },
      completed: { variant: "outline", icon: CheckCircle },
    };
    const config = variants[status] || variants.pending;
    const Icon = config.icon;
    return (
      <Badge variant={config.variant} className="gap-1">
        <Icon className="w-3 h-3" />
        {t(`booking.status.${status}`, status)}
      </Badge>
    );
  };

  const stats = {
    total: bookings.length,
    pending: bookings.filter((b) => b.status === "pending").length,
    confirmed: bookings.filter((b) => b.status === "confirmed").length,
    cancelled: bookings.filter((b) => b.status === "cancelled").length,
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <CalendarDays className="h-6 w-6 text-primary" />
          <h1 className="text-2xl font-bold">{t("admin.bookings.title", "预订记录管理")}</h1>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {[
          { label: t("admin.bookings.total", "总预订"), value: stats.total, color: "text-foreground" },
          { label: t("booking.status.pending"), value: stats.pending, color: "text-yellow-600" },
          { label: t("booking.status.confirmed"), value: stats.confirmed, color: "text-green-600" },
          { label: t("booking.status.cancelled"), value: stats.cancelled, color: "text-red-600" },
        ].map((s) => (
          <div key={s.label} className="bg-card rounded-lg border p-4">
            <p className="text-sm text-muted-foreground">{s.label}</p>
            <p className={`text-2xl font-bold ${s.color}`}>{s.value}</p>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder={t("admin.bookings.searchPlaceholder", "搜索餐厅、客人姓名、邮箱...")}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-full sm:w-40">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{t("common.all", "全部")}</SelectItem>
            <SelectItem value="pending">{t("booking.status.pending")}</SelectItem>
            <SelectItem value="confirmed">{t("booking.status.confirmed")}</SelectItem>
            <SelectItem value="cancelled">{t("booking.status.cancelled")}</SelectItem>
            <SelectItem value="completed">{t("booking.status.completed")}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Table */}
      {loading ? (
        <div className="flex items-center justify-center h-40">
          <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
        </div>
      ) : bookings.length === 0 ? (
        <div className="text-center py-12 text-muted-foreground">
          {t("admin.bookings.noRecords", "暂无预订记录")}
        </div>
      ) : (
        <div className="border rounded-lg overflow-x-auto">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("admin.bookings.restaurant", "餐厅")}</TableHead>
                <TableHead>{t("admin.bookings.guest", "客人")}</TableHead>
                <TableHead>{t("booking.form.date")}</TableHead>
                <TableHead>{t("booking.form.time")}</TableHead>
                <TableHead className="text-center">
                  <Users className="w-4 h-4 inline" />
                </TableHead>
                <TableHead>{t("common.status", "状态")}</TableHead>
                <TableHead className="w-32">{t("common.actions", "操作")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {bookings.map((booking) => (
                <TableRow key={booking.id}>
                  <TableCell className="font-medium max-w-[180px] truncate">
                    {booking.restaurant_name}
                  </TableCell>
                  <TableCell className="max-w-[150px] truncate">
                    {booking.customer_name || booking.customer_email}
                  </TableCell>
                  <TableCell className="whitespace-nowrap">{booking.booking_date}</TableCell>
                  <TableCell>{booking.booking_time}</TableCell>
                  <TableCell className="text-center">{booking.party_size}</TableCell>
                  <TableCell>{statusBadge(booking.status)}</TableCell>
                  <TableCell>
                    <div className="flex items-center gap-1">
                      <Button
                        size="icon"
                        variant="ghost"
                        className="h-8 w-8"
                        onClick={() => setSelectedBooking(booking)}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      {booking.status === "pending" && (
                        <>
                          <Button
                            size="icon"
                            variant="ghost"
                            className="h-8 w-8 text-green-600 hover:text-green-700"
                            disabled={updatingId === booking.id}
                            onClick={() => updateStatus(booking.id, "confirmed")}
                          >
                            <CheckCircle className="h-4 w-4" />
                          </Button>
                          <Button
                            size="icon"
                            variant="ghost"
                            className="h-8 w-8 text-red-600 hover:text-red-700"
                            disabled={updatingId === booking.id}
                            onClick={() => updateStatus(booking.id, "cancelled")}
                          >
                            <XCircle className="h-4 w-4" />
                          </Button>
                        </>
                      )}
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
      )}

      {/* Detail Dialog */}
      <Dialog open={!!selectedBooking} onOpenChange={(open) => !open && setSelectedBooking(null)}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>{t("admin.bookings.detail", "预订详情")}</DialogTitle>
          </DialogHeader>
          {selectedBooking && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-3 text-sm">
                <div>
                  <p className="text-muted-foreground">{t("admin.bookings.restaurant", "餐厅")}</p>
                  <p className="font-medium">{selectedBooking.restaurant_name}</p>
                </div>
                <div>
                  <p className="text-muted-foreground">{t("common.status", "状态")}</p>
                  <div className="mt-0.5">{statusBadge(selectedBooking.status)}</div>
                </div>
                <div>
                  <p className="text-muted-foreground">{t("booking.form.guestName")}</p>
                  <p className="font-medium">{selectedBooking.customer_name || "-"}</p>
                </div>
                <div>
                  <p className="text-muted-foreground">{t("booking.form.email")}</p>
                  <p className="font-medium break-all">{selectedBooking.customer_email}</p>
                </div>
                <div>
                  <p className="text-muted-foreground">{t("booking.form.phone")}</p>
                  <p className="font-medium">{selectedBooking.customer_phone || "-"}</p>
                </div>
                <div>
                  <p className="text-muted-foreground">{t("booking.form.partySize")}</p>
                  <p className="font-medium">{selectedBooking.party_size} {t("booking.people")}</p>
                </div>
                <div>
                  <p className="text-muted-foreground">{t("booking.form.date")}</p>
                  <p className="font-medium">{selectedBooking.booking_date}</p>
                </div>
                <div>
                  <p className="text-muted-foreground">{t("booking.form.time")}</p>
                  <p className="font-medium">{selectedBooking.booking_time}</p>
                </div>
              </div>
              {selectedBooking.notes && (
                <div>
                  <p className="text-sm text-muted-foreground">{t("booking.form.specialRequests")}</p>
                  <p className="text-sm mt-1 p-2 bg-muted rounded">{selectedBooking.notes}</p>
                </div>
              )}
              <div>
                <p className="text-xs text-muted-foreground">
                  {t("admin.bookings.createdAt", "提交时间")}: {format(new Date(selectedBooking.created_at), "yyyy-MM-dd HH:mm")}
                </p>
              </div>
              {selectedBooking.status === "pending" && (
                <div className="flex gap-2 pt-2">
                  <Button
                    className="flex-1"
                    disabled={updatingId === selectedBooking.id}
                    onClick={() => updateStatus(selectedBooking.id, "confirmed")}
                  >
                    <CheckCircle className="w-4 h-4 mr-1" />
                    {t("booking.status.confirmed")}
                  </Button>
                  <Button
                    variant="destructive"
                    className="flex-1"
                    disabled={updatingId === selectedBooking.id}
                    onClick={() => updateStatus(selectedBooking.id, "cancelled")}
                  >
                    <XCircle className="w-4 h-4 mr-1" />
                    {t("booking.status.cancelled")}
                  </Button>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default AdminBookings;
